def summarize_search(response):
    items = response.get("items", [])
    lines = []
    for repo in items:
        name = repo.get("name", "<unnamed>")
        stars = repo.get("stargazers_count", 0)
        owner = repo.get("owner", {}).get("login", "<unknown>")
        lines.append(f"{name} (★{stars}) — {owner}")
    return lines

response = {
    "total_count": 3,
    "items": [
        {"name": "fastapi", "owner": {"login": "tiangolo"}, "stargazers_count": 70000},
        {"name": "httpx", "owner": {"login": "encode"}, "stargazers_count": 12000},
        {"name": "mystery-repo", "stargazers_count": 5},
    ],
}

for line in summarize_search(response):
    print(line)
